### syscall constants
PRINT_STRING            = 4
PRINT_CHAR              = 11
PRINT_INT               = 1

### MMIO addrs
ANGLE                   = 0xffff0014
ANGLE_CONTROL           = 0xffff0018
VELOCITY                = 0xffff0010

REQUEST_PUZZLE          = 0xffff00d0
AVAIL_PUZZLES           = 0xffff00b4
CURRENT_PUZZLE          = 0xffff00b8
PUZZLE_FEEDBACK         = 0xffff00e0
SUBMIT_SOLUTION         = 0xffff00d4

BOT_X                   = 0xffff0020
BOT_Y                   = 0xffff0024

NUM_CARROTS             = 0xffff0040
NUM_BUNNIES_CARRIED     = 0xffff0050

SEARCH_BUNNIES          = 0xffff0054
CATCH_BUNNY             = 0xffff0058
PUT_BUNNIES_IN_PLAYPEN  = 0xffff005c

PLAYPEN_LOCATION        = 0xffff0044

SCORES_REQUEST          = 0xffff1018

TIMER                   = 0xffff001c

BONK_INT_MASK           = 0x1000        ## Bonk
BONK_ACK                = 0xffff0060    ## Bonk
TIMER_INT_MASK          = 0x8000        ## Timer
TIMER_ACK               = 0xffff006c    ## Timer
BUNNY_MOVE_INT_MASK     = 0x400         ## Bunny Move
BUNNY_MOVE_ACK          = 0xffff00e8    ## Bunny Move
EX_CARRY_LIMIT_INT_MASK = 0x4000        ## Exceeding Carry Limit
EX_CARRY_LIMIT_ACK      = 0xffff002c    ## Exceeding Carry Limit
REQUEST_PUZZLE_INT_MASK = 0x0800        ## Request Puzzle
REQUEST_PUZZLE_ACK      = 0xffff00e4    ## Request Puzzle

MMIO_STATUS             = 0xffff204c

BOT_SPEED               = 10
BUNNIES_TO_CATCH        = 10
THRESHOLD				= 400000

.data
.align 4
bunnies_info: .space 484                    # Space for the BunniesInfo Struct

puzzle: .space 268                          # Space for the LightsOut Puzzle

solution: .space 256                        # Space for the solution to the LightsOut Puzzle

num_puzzles_requested: .word 0              # The number of puzzle that habve been requested

.align 1
has_bonked: .byte 0                         # Bonk Interrupt

puzzle_received: .byte 0                    # Puzzle Received Interrupt

playpen_x: .word 0                                  # The x-cooridnate of our playpen
playpen_y: .word 0                                  # The y-cooridnate of our playpen

.text
main:
    # enable interrupts
    li      $t4     1
    or      $t4     $t4     TIMER_INT_MASK
    or      $t4,    $t4,    BONK_INT_MASK               # enable bonk interrupt
    or      $t4,    $t4,    REQUEST_PUZZLE_INT_MASK     # enable request puzzle interrupt
    or      $t4,    $t4,    1                           # global enable
    mtc0    $t4     $12

    li $t1, 0
    sw $t1, ANGLE
    li $t1, 1
    sw $t1, ANGLE_CONTROL
    li $t2, 0
    sw $t2, VELOCITY

    ##############################
    # Save the playpen location to memory
    lw $t0, PLAYPEN_LOCATION
    and $t1, $t0, 0xFFFF0000
    srl $t1, $t1, 16
    and $t2, $t0, 0x0000FFFF
    la $t3, playpen_y
    sw $t1, 0($t3)
    la $t4, playpen_x
    sw $t2, 0($t4)

    la      $t0, playpen_x                  # $t0 = &playpen_x
    lw      $a0, 0($t0)                     # $a0 = playpen_x | Extract x coordinate
    lw      $a1, 4($t0)                     # $a1 = playpen_y | Extract y coordinate

    lw      $t8, BOT_X
    lw      $t9, BOT_Y

    sub     $t0, $a0, $t8                   # deltaX
    sub     $t1, $a1, $t9                   # deltaY

    mul     $t2, $t0, 601
    add     $t2, $t2, $t1
    mul     $t2, $t2, 4
    la      $t3, atan2lookup
    add     $t3, $t3, $t2
    lw      $t4, 0($t3)                     # $t4 = theta
    sw      $t4, ANGLE
    li      $t5, 1
    sw      $t5, ANGLE_CONTROL

    move    $t6, $a0
    move    $t7, $a1

    move    $a0, $t8
    move    $a1, $t9
    move    $a2, $0
    jal     print_xy

    move    $a0, $t6
    move    $a1, $t7
    move    $a2, $0
    jal     print_xy

    move    $a0, $t4
    move    $a1, $0
    move    $a2, $0
    jal     print_xy

    # mul     $t5, $t5, $t5
    # mul     $t6, $t6, $t6
